+final class LazyAudioRecorder: AudioRecording, @unchecked Sendable {
+    private let makeRecorder: () -> any AudioRecording
+    private let lock = NSLock()
+    private var recorder: (any AudioRecording)?
+
+    init(makeRecorder: @escaping () -> any AudioRecording) {
+        self.makeRecorder = makeRecorder
+    }
+
+    var isRecording: Bool {
+        currentRecorder()?.isRecording ?? false
+    }
+
+    var bufferedSampleCount: Int {
+        currentRecorder()?.bufferedSampleCount ?? 0
+    }
+
+    func prewarm() throws {
+        try resolvedRecorder().prewarm()
+    }
+
+    func startRecording(onChunk: @escaping AudioChunkHandler) throws {
+        try resolvedRecorder().startRecording(onChunk: onChunk)
+    }
+
+    func clearBufferedSamples() {
+        currentRecorder()?.clearBufferedSamples()
+    }
+
+    func stopRecording() async -> [Float] {
+        guard let recorder = currentRecorder() else {
+            return []
+        }
+
+        return await recorder.stopRecording()
+    }
+
+    private func currentRecorder() -> (any AudioRecording)? {
+        lock.lock()
+        defer { lock.unlock() }
+        return recorder
+    }
+
+    private func resolvedRecorder() -> any AudioRecording {
+        lock.lock()
+        defer { lock.unlock() }
+
+        if let recorder {
+            return recorder
+        }
+
+        let recorder = makeRecorder()
+        self.recorder = recorder
+        return recorder
+    }
+}
